var items = $input.all();
var results = [];
var now = new Date().toISOString();
for (var i = 0; i < items.length; i++) {
  var data = items[i].json;
  var title = data.title || data.name || 'Untitled';
  var link = data.link || data.url || data.guid || '';
  var summary = (data.contentSnippet || data.content || data.description || '').replace(/<[^>]*>/g,'').trim();
  var source = data.creator || data.author || 'Unknown';
  var published = data.pubDate || data.isoDate || data.date || now;
  var category = 'sector-news';
  var priority = 3;
  var text = (title + ' ' + summary).toLowerCase();
  if (/\bherm\b|enterprise resource|erp|student information system|sis|mis |management information/.test(text)) { category='herm-updates'; priority=1; }
  else if (/tribal|ellucian|unit4|technologyone|aptem|\bsits\b|banner|workday|oracle student|campus solution|colleague|peoplesoft/.test(text)) { category='vendor-intelligence'; priority=1; }
  else if (/launch|release|new version|update|announced|available now|product|feature|integration/.test(text)) { category='product-launches'; priority=2; }
  else if (/\bofs\b|office for students|\bhesa\b|\btef\b|\bref\b|regulatory|compliance|statutory|nss|graduate outcome|registration condition/.test(text)) { category='regulatory-compliance'; priority=2; }
  else if (/\bai\b|artificial intelligence|machine learning|edtech|ed.tech|learning analytic|chatgpt|generative|llm|automation/.test(text)) { category='ai-higher-education'; priority=2; }
  results.push({json:{title:title,link:link,summary:summary.substring(0,300),source:source,published:published,category:category,priority:priority}});
}
results.sort(function(a,b){return a.json.priority - b.json.priority;});
return results;

var now = new Date().toLocaleDateString('en-GB',{weekday:'long',year:'numeric',month:'long',day:'numeric'});
var allItems = $('Categorise Sector News').all();
var groups = {};
for (var i=0;i<allItems.length;i++){
  var c=allItems[i].json.category||'other';
  if(!groups[c])groups[c]=[];
  groups[c].push(allItems[i].json);
}
var labels={
  'herm-updates':'🏫 HERM Model & ERP Updates',
  'vendor-intelligence':'🏢 Vendor Intelligence (Tribal/Ellucian/Unit4/Workday)',
  'product-launches':'🚀 Product Launches & Updates',
  'regulatory-compliance':'📜 Regulatory & Compliance (OfS/HESA/TEF/REF)',
  'ai-higher-education':'🤖 AI in Higher Education',
  'sector-news':'📰 Sector News & Analysis',
  'other':'📌 Other'
};
var order=['herm-updates','vendor-intelligence','product-launches','regulatory-compliance','ai-higher-education','sector-news','other'];
var html='<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">';
html+='<div style="background:#1a3a5c;color:#fff;padding:20px;border-radius:6px 6px 0 0;">';
html+='<h1 style="margin:0;font-size:1.4em;">🎓 HERM & HE Landscape Intelligence Digest</h1>';
html+='<p style="margin:5px 0 0;opacity:0.8;">Week of '+now+'</p></div>';
for(var ci=0;ci<order.length;ci++){
  var cat=order[ci];
  var entries=groups[cat];
  if(!entries||!entries.length)continue;
  html+='<div style="padding:15px 20px;border-bottom:2px solid #eee;">';
  html+='<h2 style="color:#1a3a5c;font-size:1.1em;margin:0 0 10px;">'+(labels[cat]||cat)+' ('+entries.length+')</h2>';
  html+='<ul style="padding-left:20px;margin:0;">';
  for(var e=0;e<entries.length;e++){
    html+='<li style="margin-bottom:8px;">';
    html+='<strong><a href="'+entries[e].link+'" style="color:#1a3a5c;">'+entries[e].title+'</a></strong>';
    if(entries[e].summary)html+='<br><span style="color:#555;font-size:0.9em;">'+entries[e].summary.substring(0,200)+'</span>';
    html+='<br><small style="color:#999;">'+entries[e].source+'</small></li>';
  }
  html+='</ul></div>';
}
html+='<p style="color:#999;font-size:0.8em;padding:10px 20px;">Generated by Workhorse &bull; '+now+'</p></div>';
return [{json:{subject:'HERM Landscape Digest — '+now,html:html,itemCount:allItems.length}}];
